var expect = require('expect.js');
var SelectResource = require('../../res/page/selectresource/selectresource');

describe('sqlscan-selectresource', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init selectresource()', function(){
    it('init selectresource', function(done){
      var selectresource = SelectResource._create({
        events : {
          'afterrender' : function(){
            expect(selectresource).to.be.ok();
            expect(selectresource._container).to.be.ok();
            selectresource._container.on('afterresourcelistload', function(){
              var sourcelist = this.query('list[name="sourcelist"]');
              expect(sourcelist).to.be.ok();
              expect(sourcelist.store.recordCount).to.be(9);
            });
            selectresource._container.on('showcreateresourcewin', function(){
              expect(this.createWin).to.be.ok();
            });
            selectresource._container.on('aftercomplete', function(){
              var btnCreate = this.query('button[name=btnCreateSourceBySelect]');
              expect(btnCreate).to.be.ok();
              expect(this.createWin).not.to.be.ok();
              btnCreate.emit('click');
            });
            done();
          }
        }
      });
    });
  });
  describe('#selectresource events', function(){
    it('selectresource events', function(done){
      var selectresource = SelectResource._create({
        events : {
          'afterrender' : function(){
            var _self = this;
            expect(selectresource).to.be.ok();
            expect(selectresource._container).to.be.ok();
            selectresource._container.on('aftercomplete', function(){
              this.on('afterresourcelistload', function(){
                var sourcelist = this.query('list[name="sourcelist"]');
                expect(sourcelist).to.be.ok();
                expect(sourcelist.store.recordCount).to.be(9);
                var btnSelectSourceSure = this.query('button[name="btnSelectSourceSure"]');
                btnSelectSourceSure.emit('click');
                expect(this.checkValueTest).to.be('请选择资源名!');
                this.setResource([{id:1,name:"test"}]);
                expect(this.checkValueTest).to.be(null);
                var btnSelectSourceCancel = this.query('button[name="btnSelectSourceCancel"]');
                //expect(this.win).to.be.ok();
                btnSelectSourceCancel.emit('click');
                expect(this.win).to.be(null);
              });
              var btnSearch = this.query('search[name="btnSearch"]');
              btnSearch.emit('click');
              done();
            });
          }
        }
      });
    });
  });
});